/* Wait-Type-Katalog: normalisierter Seed-Teil 04 von 04. */
DECLARE @Seed TABLE
([WaitType] nvarchar(120),[WaitGroup] nvarchar(64),[Severity] tinyint,[IsGenerallyBenign] bit,[Meaning] nvarchar(1000),
