INSERT @Seed VALUES
(N'RESOURCE_SEMAPHORE_SMALL_QUERY',N'MEMORY',2,0,N'Occurs when memory request by a small query cannot be granted immediately due to other concurrent queries. Wait time should not exceed more than a few seconds, because the server transfers the request to the main query memory pool if it fails to grant the',N'Speicherzuteilung, Memory Grants oder interne Memory-Manager.',N'Hohe Werte verzögern Start oder Ausführung von Abfragen.',N'Pending Grants, Grantgrößen, Cardinality, Spills und max server memory prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SECURITY_MUTEX',N'OTHER_OR_NEW',2,0,N'Occurs when there is a wait for mutexes that control access to the global list of Extensible Key Management (EKM) cryptographic providers and the session-scoped list of EKM sessions.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SEC_DROP_TEMP_KEY',N'OTHER_OR_NEW',2,0,N'Occurs after a failed attempt to drop a temporary security key before a retry attempt.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SEQUENTIAL_GUID',N'OTHER_OR_NEW',2,0,N'Occurs while a new sequential GUID is being obtained.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SERVER_IDLE_CHECK',N'BENIGN_BACKGROUND',0,1,N'Occurs during synchronization of SQL Server instance idle status when a resource monitor is attempting to declare a SQL Server instance as idle or trying to wake up.',N'Normaler Idle-, Timer-, Queue- oder Hintergrundzustand.',N'Hohe kumulative Werte sind in der Regel erwartbar und kein Engpassbeweis.',N'Standardmäßig aus Top-Ranking ausblenden; nur bei passender Funktionsstörung untersuchen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SHUTDOWN',N'OTHER_OR_NEW',2,0,N'Dieser Wartetyp weist darauf hin, dass ein SHUTDOWN-Befehl durch die SPID ausgegeben wurde und dass die SPID darauf wartet, dass aktive Abfragen abgeschlossen werden. (Occurs while a shutdown statement waits for active connections to exit.)',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SLEEP',N'BENIGN_BACKGROUND',0,1,N'Dieser Wartetyp weist darauf hin, dass die SPID für eine festgelegte Zeitspanne wartet und ist ein häufiger Zustand für im Hintergrund ausgeführte Threads, die Lazywrites, Prüfpunkte oder serverseitige Profiler-Ablaufverfolgungen verarbeiten.',N'Normaler Idle-, Timer-, Queue- oder Hintergrundzustand.',N'Hohe kumulative Werte sind in der Regel erwartbar und kein Engpassbeweis.',N'Standardmäßig aus Top-Ranking ausblenden; nur bei passender Funktionsstörung untersuchen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SLEEP_BPOOL_FLUSH',N'BENIGN_BACKGROUND',0,1,N'Occurs when a checkpoint is throttling the issuance of new I/Os in order to avoid flooding the disk subsystem.',N'Normaler Idle-, Timer-, Queue- oder Hintergrundzustand.',N'Hohe kumulative Werte sind in der Regel erwartbar und kein Engpassbeweis.',N'Standardmäßig aus Top-Ranking ausblenden; nur bei passender Funktionsstörung untersuchen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'SLEEP_DBSTARTUP',N'BENIGN_BACKGROUND',0,1,N'Occurs during database startup while waiting for all databases to recover.',N'Normaler Idle-, Timer-, Queue- oder Hintergrundzustand.',N'Hohe kumulative Werte sind in der Regel erwartbar und kein Engpassbeweis.',N'Standardmäßig aus Top-Ranking ausblenden; nur bei passender Funktionsstörung untersuchen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
